import pytest
from autogen import AssistantAgent, UserProxyAgent

def mock_assistant_llm(messages, **kwargs):
    """Returns a deterministic mock reply for testing."""
    last = messages[-1].get("content", "")
    if "mean" in last.lower():
        return {"content": "The mean is 50. TERMINATE", "role": "assistant"}
    return {"content": "I will compute that. TERMINATE", "role": "assistant"}

def test_assistant_terminates():
    assistant = AssistantAgent("assistant", llm_config=False, human_input_mode="NEVER")
    assistant.register_reply(
        trigger=None,   # match any sender
        reply_func=lambda r, msgs, s, cfg: (True, "Answer here. TERMINATE"),
        position=0,
    )
    user_proxy = UserProxyAgent(
        name="user",
        human_input_mode="NEVER",
        code_execution_config=False,
        is_termination_msg=lambda m: "TERMINATE" in (m.get("content") or ""),
    )
    result = user_proxy.initiate_chat(assistant, message="What is 2+2?", max_turns=3)
    assert "Answer here" in result.summary
